content:
{
  "sentences": [
    {
      "text": "這家餐廳的價格跟那家差不多。",
      "pinyin": "Zhè jiā cāntīng de jiàgé gēn nà jiā chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de5 jia4ge2 gen1 na4 jia1 cha4bu4duo1",
      "translation_en": "The price of this restaurant is about the same as that one.",
      "translation_ko": "이 식당의 가격은 저 식당과 비슷합니다."
    },
    {
      "text": "牛肉麵的味道跟滷肉飯差不多。",
      "pinyin": "Niúròu miàn de wèidào gēn lǔròu fàn chàbùduō.",
      "pinyin_numeric": "niu2rou4 mian4 de5 wei4dao4 gen1 lu3rou4 fan4 cha4bu4duo1",
      "translation_en": "The flavor of beef noodles is similar to that of braised pork rice.",
      "translation_ko": "소고기 국수의 맛은 루로우판과 비슷합니다."
    },
    {
      "text": "便利商店的咖啡跟咖啡店的差不多。",
      "pinyin": "Biànlì shāngdiàn de kāfēi gēn kāfēi diàn de chàbùduō.",
      "pinyin_numeric": "bian4li4 shang1dian4 de5 ka1fei1 gen1 ka1fei1 dian4 de5 cha4bu4duo1",
      "translation_en": "The coffee at convenience stores is about the same as at coffee shops.",
      "translation_ko": "편의점 커피는 커피숍 커피와 비슷합니다."
    },
    {
      "text": "這份炒飯的份量跟那份差不多。",
      "pinyin": "Zhè fèn chǎofàn de fènliàng gēn nà fèn chàbùduō.",
      "pinyin_numeric": "zhe4 fen4 chao3fan4 de5 fen4liang4 gen1 na4 fen4 cha4bu4duo1",
      "translation_en": "The portion of this fried rice is about the same as that one.",
      "translation_ko": "이 볶음밥의 양은 저 볶음밥과 비슷합니다."
    },
    {
      "text": "捷運站到公司的距離跟到學校差不多。",
      "pinyin": "Jiéyùn zhàn dào gōngsī de jùlí gēn dào xuéxiào chàbùduō.",
      "pinyin_numeric": "jie2yun4 zhan4 dao4 gong1si1 de5 ju4li2 gen1 dao4 xue2xiao4 cha4bu4duo1",
      "translation_en": "The distance from the MRT station to the company is about the same as to the school.",
      "translation_ko": "지하철역에서 회사까지의 거리는 학교까지와 비슷합니다."
    },
    {
      "text": "這家店的服務態度跟那家差不多。",
      "pinyin": "Zhè jiā diàn de fúwù tàidù gēn nà jiā chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 dian4 de5 fu2wu4 tai4du4 gen1 na4 jia1 cha4bu4duo1",
      "translation_en": "The service attitude at this store is about the same as that one.",
      "translation_ko": "이 가게의 서비스 태도는 저 가게와 비슷합니다."
    },
    {
      "text": "夜市的小吃跟小吃店的差不多。",
      "pinyin": "Yèshì de xiǎochī gēn xiǎochī diàn de chàbùduō.",
      "pinyin_numeric": "ye4shi4 de5 xiao3chi1 gen1 xiao3chi1 dian4 de5 cha4bu4duo1",
      "translation_en": "The snacks at the night market are about the same as those at the snack shop.",
      "translation_ko": "야시장의 간식은 분식점의 간식과 비슷합니다."
    },
    {
      "text": "這杯紅茶的甜度跟那杯差不多。",
      "pinyin": "Zhè bēi hóngchá de tiándù gēn nà bēi chàbùduō.",
      "pinyin_numeric": "zhe4 bei1 hong2cha2 de5 tian2du4 gen1 na4 bei1 cha4bu4duo1",
      "translation_en": "The sweetness of this cup of black tea is about the same as that one.",
      "translation_ko": "이 홍차의 단맛은 저 홍차와 비슷합니다."
    },
    {
      "text": "這家餐廳的環境跟那家差不多。",
      "pinyin": "Zhè jiā cāntīng de huánjìng gēn nà jiā chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de5 huan2jing4 gen1 na4 jia1 cha4bu4duo1",
      "translation_en": "The atmosphere of this restaurant is about the same as that one.",
      "translation_ko": "이 식당의 분위기는 저 식당과 비슷합니다."
    },
    {
      "text": "坐公車跟坐捷運的時間差不多。",
      "pinyin": "Zuò gōngchē gēn zuò jiéyùn de shíjiān chàbùduō.",
      "pinyin_numeric": "zuo4 gong1che1 gen1 zuo4 jie2yun4 de5 shi2jian1 cha4bu4duo1",
      "translation_en": "Taking the bus and taking the MRT take about the same amount of time.",
      "translation_ko": "버스를 타는 것과 지하철을 타는 시간이 비슷합니다."
    }
  ]
}
